record.field:
{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo technical model name. Common: sale.order, account.move, purchase.order, hr.payslip, stock.picking, mrp.production"
        },
        "report_xmlid": {
            "type": "string",
            "description": "Report external ID. Use EXACTLY: 'sale.action_report_saleorder' (quotation/order), 'account.account_invoices' (invoice), 'purchase.report_purchaseorder' (PO), 'hr_payroll.action_report_payslip' (payslip), 'stock.action_report_delivery' (delivery), 'mrp.action_report_production_order' (manufacturing). Do NOT use window action IDs."
        },
        "document_name": {
            "type": "string",
            "description": "Reference number like S00001, INV/2026/00001. Empty string if searching by partner or date instead."
        },
        "partner_name": {
            "type": "string",
            "description": "Customer, vendor, or employee name. Used when user says 'Rocky's invoice' or 'John's payslip'. Empty string if not applicable."
        },
        "date_from": {
            "type": "string",
            "description": "Start date in YYYY-MM-DD format, e.g. 2026-06-01. Empty string if not filtering by date."
        },
        "date_to": {
            "type": "string",
            "description": "End date in YYYY-MM-DD format, e.g. 2026-06-30. Empty string if not filtering by date."
        }
    },
    "required": ["model_name", "report_xmlid", "document_name", "partner_name", "date_from", "date_to"]
}

# ── Model config: date field + partner field per model ──
DATE_FIELD = {
    'sale.order':      'date_order',
    'account.move':    'invoice_date',
    'purchase.order':  'date_order',
    'hr.payslip':      'date_from',
    'stock.picking':   'scheduled_date',
    'mrp.production':  'date_start',
}
PARTNER_CONFIG = {
    'sale.order':      ('res.partner',  'partner_id'),
    'account.move':    ('res.partner',  'partner_id'),
    'purchase.order':  ('res.partner',  'partner_id'),
    'hr.payslip':      ('hr.employee',  'employee_id'),
    'stock.picking':   ('res.partner',  'partner_id'),
    'mrp.production':  ('res.partner',  'partner_id'),
}

# ── Build search domain ──
domain = []
error = None

if document_name:
    domain.append(['name', 'ilike', document_name])

if partner_name:
    if model_name in PARTNER_CONFIG:
        rel_model, rel_field = PARTNER_CONFIG[model_name]
        related = env[rel_model].sudo().search([['name', 'ilike', partner_name]], limit=5)
        if not related:
            error = f"Cannot find '{partner_name}' in {rel_model}. Please check the name."
        else:
            domain.append([rel_field, 'in', related.ids])
    else:
        error = f"Partner search not supported for model {model_name}."

if not error and date_from:
    df = DATE_FIELD.get(model_name, 'date')
    domain.append([df, '>=', date_from])

if not error and date_to:
    df = DATE_FIELD.get(model_name, 'date')
    domain.append([df, '<=', date_to])

if not error and not domain:
    error = "Please provide at least one search criterion: document_name, partner_name, or date range."

# ── Execute ──
if error:
    ai['result'] = f"ERROR: {error}"
else:
    docs = env[model_name].sudo().search(domain, limit=5)

    if not docs:
        ai['result'] = f"No records found in {model_name} matching the criteria."
    else:
        base_url = env['ir.config_parameter'].sudo().get_param('web.base.url')

        # ── Build HTML: one link per record ──
        if len(docs) == 1:
            doc = docs[0]
            pdf_url = f"{base_url}/report/pdf/{report_xmlid}/{doc.id}"
            body_html = (
                f'<p><b style="color:#8e44ad">Here is the PDF for {doc.display_name}:</b></p>'
                f'<p><a href="{pdf_url}" target="_blank" style="color:#e67e22;font-weight:600">'
                f'&#128196; Download {doc.display_name}.pdf</a></p>'
            )
        else:
            links = "".join(
                f'<p><a href="{base_url}/report/pdf/{report_xmlid}/{d.id}" '
                f'target="_blank" style="color:#e67e22;font-weight:600">'
                f'&#128196; {d.display_name}</a></p>'
                for d in docs
            )
            body_html = (
                f'<p><b style="color:#8e44ad">Found {len(docs)} records — PDF links:</b></p>'
                + links
            )

        channel = env.context.get('discuss_channel')
        if channel:
            record.sudo().post_html_to_channel(channel, body_html)
            names = ", ".join(d.display_name for d in docs)
            ai['result'] = f"Sent {len(docs)} PDF link(s) to chat: {names}"
        else:
            links_text = "\n".join(
                f"{d.display_name}: {base_url}/report/pdf/{report_xmlid}/{d.id}"
                for d in docs
            )
            ai['result'] = f"PDF links:\n{links_text}"

{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo model. Supported: sale.order (quotation), account.move (invoice/bill), purchase.order, stock.picking (delivery/transfer), mrp.production (manufacturing), account.payment, hr.expense.sheet"
        },
        "document_name": {
            "type": "string",
            "description": "Reference number e.g. S00001, INV/2026/00001, P00001. Empty string if searching by partner."
        },
        "partner_name": {
            "type": "string",
            "description": "Customer/vendor name to find the document. Empty string if using document_name."
        }
    },
    "required": ["model_name", "document_name", "partner_name"]
}

# ── Config: valid states + label per model ──
CONFIRM_CONFIG = {
    'sale.order':       (['draft', 'sent'],               'Quotation'),
    'account.move':     (['draft'],                        'Invoice/Bill'),
    'purchase.order':   (['draft', 'sent'],                'Purchase Order'),
    'stock.picking':    (['assigned', 'waiting', 'confirmed'], 'Transfer'),
    'mrp.production':   (['draft'],                        'Manufacturing Order'),
    'account.payment':  (['draft'],                        'Payment'),
    'hr.expense.sheet': (['draft'],                        'Expense Report'),
}
PARTNER_FIELD = {
    'sale.order': 'partner_id', 'account.move': 'partner_id',
    'purchase.order': 'partner_id', 'stock.picking': 'partner_id',
    'account.payment': 'partner_id',
}

if model_name not in CONFIRM_CONFIG:
    ai['result'] = (
        f"ERROR: Confirm not supported for '{model_name}'.\n"
        f"Supported: {', '.join(CONFIRM_CONFIG.keys())}"
    )
else:
    valid_states, label = CONFIRM_CONFIG[model_name]

    # ── Build domain ──
    domain = [['state', 'in', valid_states]]
    error = None

    if document_name:
        domain.append(['name', 'ilike', document_name])
    elif partner_name and model_name in PARTNER_FIELD:
        partner = env['res.partner'].sudo().search(
            [['name', 'ilike', partner_name]], limit=5
        )
        if not partner:
            error = f"Cannot find customer/vendor '{partner_name}'."
        else:
            domain.append([PARTNER_FIELD[model_name], 'in', partner.ids])
    elif not document_name:
        error = "Please provide document_name or partner_name."

    if error:
        ai['result'] = f"ERROR: {error}"
    else:
        docs = env[model_name].sudo().search(domain, limit=5)

        if not docs:
            ai['result'] = f"No {label} in confirmable state ({', '.join(valid_states)}) found."
        elif len(docs) > 1:
            names = ", ".join(d.display_name for d in docs)
            ai['result'] = (
                f"Found {len(docs)} {label}s: {names}\n"
                f"Please specify the exact reference number to avoid confirming the wrong one."
            )
        else:
            doc = docs[0]
            confirmed_name = doc.display_name

            # ── Call confirm method per model ──
            if model_name == 'sale.order':
                doc.action_confirm()
            elif model_name == 'account.move':
                doc.action_post()
            elif model_name == 'purchase.order':
                doc.button_confirm()
            elif model_name == 'stock.picking':
                doc.with_context(immediate_transfer=True).button_validate()
            elif model_name == 'mrp.production':
                doc.action_confirm()
            elif model_name == 'account.payment':
                doc.action_post()
            elif model_name == 'hr.expense.sheet':
                doc.action_submit_sheet()

            ai['result'] = (
                f"{label} {confirmed_name} confirmed successfully.\n"
                f"  Status: {doc.state}"
            )

{
    "type": "object",
    "properties": {
        "model_name": {
            "type": "string",
            "description": "Odoo model. Supported: sale.order (quotation/order), account.move (invoice), purchase.order"
        },
        "document_name": {
            "type": "string",
            "description": "Reference number e.g. S00001, INV/2026/00001. Empty string if searching by partner."
        },
        "partner_name": {
            "type": "string",
            "description": "Customer/vendor name to find the document. Empty string if using document_name."
        }
    },
    "required": ["model_name", "document_name", "partner_name"]
}

# ── Email template xmlid per model ──
EMAIL_TEMPLATES = {
    'sale.order':     'sale.email_template_edi_sale',
    'account.move':   'account.email_template_edi_invoice',
    'purchase.order': 'purchase.email_template_edi_purchase',
}
PARTNER_FIELD = {
    'sale.order': 'partner_id',
    'account.move': 'partner_id',
    'purchase.order': 'partner_id',
}

if model_name not in EMAIL_TEMPLATES:
    ai['result'] = (
        f"ERROR: Email sending not supported for '{model_name}'.\n"
        f"Supported: {', '.join(EMAIL_TEMPLATES.keys())}"
    )
else:
    # ── Build domain ──
    domain = []
    error = None

    if document_name:
        domain.append(['name', 'ilike', document_name])
    elif partner_name:
        partner = env['res.partner'].sudo().search(
            [['name', 'ilike', partner_name]], limit=5
        )
        if not partner:
            error = f"Cannot find customer/vendor '{partner_name}'."
        else:
            domain.append([PARTNER_FIELD[model_name], 'in', partner.ids])
    else:
        error = "Please provide document_name or partner_name."

    if error:
        ai['result'] = f"ERROR: {error}"
    else:
        docs = env[model_name].sudo().search(domain, limit=5)

        if not docs:
            ai['result'] = f"No record found in {model_name} matching the criteria."
        elif len(docs) > 1:
            names = ", ".join(d.display_name for d in docs)
            ai['result'] = (
                f"Found {len(docs)} records: {names}\n"
                f"Please specify the exact reference number to send the correct email."
            )
        else:
            doc = docs[0]

            # ── Check recipient has email ──
            partner = doc.partner_id
            if not partner or not partner.email:
                ai['result'] = (
                    f"ERROR: {doc.display_name} has no email address on the customer record.\n"
                    f"Please add an email to the contact first."
                )
            else:
                # ── Send via template ──
                template = env.ref(EMAIL_TEMPLATES[model_name])
                template.sudo().send_mail(doc.id, force_send=True)

                ai['result'] = (
                    f"Email sent successfully for {doc.display_name}.\n"
                    f"  Recipient: {partner.display_name} <{partner.email}>\n"
                    f"  Document: {doc.display_name}"
                )
